import { CanActivateFn, Router } from '@angular/router';
import { inject } from '@angular/core';
import { AuthService } from '../services/auth.service';

/** The feed requires a complete profile (bio + at least one photo). Members who
 *  have not finished onboarding are redirected to the profile-completion screen. */
export const completeProfileGuard: CanActivateFn = () => {
  const auth = inject(AuthService);
  const router = inject(Router);

  if (!auth.isLoggedIn()) {
    return router.createUrlTree(['/login']);
  }
  if (!auth.profileComplete()) {
    return router.createUrlTree(['/profile/edit'], { queryParams: { onboarding: 1 } });
  }
  return true;
};
